import { Link } from "react-router-dom";

export default function Logo({ className = "" }) {
    return (
        <Link 
            to="/" 
            className={`flex items-center gap-2 group transition-transform hover:scale-105 ${className}`}
        >
            {/* Logo Icon/Text */}
            <div className="flex flex-col items-start">
                <div className="font-serif font-bold text-espresso leading-tight">
                    <span className="text-xl md:text-2xl">ShopLive</span>
                    <span className="text-lg md:text-xl serif-italic text-champagne block">Bharat</span>
                </div>
            </div>
        </Link>
    );
}
